import{_ as a,c as s,o as i,a4 as e}from"./chunks/framework.BmdFiWrL.js";const b=JSON.parse('{"title":"前端真实 IP 请求头","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/q12.md","filePath":"guide/q12.md","lastUpdated":1780405010000}'),t={name:"guide/q12.md"},l=e(`<h1 id="前端真实-ip-请求头" tabindex="-1">前端真实 IP 请求头 <a class="header-anchor" href="#前端真实-ip-请求头" aria-label="Permalink to &quot;前端真实 IP 请求头&quot;">​</a></h1><p><strong>前端真实 IP 请求头</strong>用于让 Dashboard 识别访问管理前端和用户前端的真实客户端 IP。在线用户、登录防爆破、OAuth2 爆破防护、API Token 爆破防护、Agent 连接密钥爆破防护、审计记录和 Web 应用防火墙（WAF）都依赖这个 IP。</p><p>此功能可在管理前端 <strong>头像 → 系统设置 → 系统配置 → 前端真实 IP 请求头</strong> 中配置；对应配置文件字段为 <a href="/configuration/dashboard.html#web_real_ip_header"><code>web_real_ip_header</code></a>。</p><div class="warning custom-block"><p class="custom-block-title">前端请求头和 Agent 请求头不同</p><p><strong>前端真实 IP 请求头</strong>只处理浏览器或用户访问 Dashboard 时的 IP。<strong>Agent 真实 IP 请求头</strong>只处理 Agent 连接 Dashboard 时的 IP。两者的访问入口、代理链路和用途可能不同，请不要混用。</p></div><hr><h2 id="推荐怎么填" tabindex="-1">推荐怎么填 <a class="header-anchor" href="#推荐怎么填" aria-label="Permalink to &quot;推荐怎么填&quot;">​</a></h2><table tabindex="0"><thead><tr><th>部署方式</th><th>推荐值</th><th>说明</th></tr></thead><tbody><tr><td>Dashboard 直接公网访问</td><td><strong>使用直连 IP</strong></td><td>等价于 <code>web_real_ip_header: &quot;NZ::Use-Peer-IP&quot;</code></td></tr><tr><td>普通反向代理</td><td><code>X-Real-IP</code> 或反向代理示例中的 <code>nz-realip</code></td><td>上游 Nginx、Caddy、Apache 等必须传递同名 Header</td></tr><tr><td>Cloudflare CDN</td><td><code>CF-Connecting-IP</code></td><td>其它 CDN 请填写对应厂商提供的真实 IP Header</td></tr><tr><td>不确定代理是否正确传头</td><td>先留空或使用直连 IP</td><td>确认代理日志和 Header 后再启用自定义 Header</td></tr></tbody></table><p>只信任来自可信反向代理或 CDN 的真实 IP Header。如果 Dashboard 可以被用户绕过代理直接访问，用户可能伪造这个 Header，导致 WAF 误判或被绕过。</p><hr><h2 id="场景一-dashboard-直接公网访问" tabindex="-1">场景一：Dashboard 直接公网访问 <a class="header-anchor" href="#场景一-dashboard-直接公网访问" aria-label="Permalink to &quot;场景一：Dashboard 直接公网访问&quot;">​</a></h2><p>如果浏览器直接访问 Dashboard，没有经过 Nginx、Caddy、Apache、Cloudflare 或其它 CDN，选择 <strong>使用直连 IP</strong> 即可。</p><p>配置文件中的等价值为：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NZ::Use-Peer-IP&quot;</span></span></code></pre></div><p>此模式下 Dashboard 直接使用连接 IP，不需要上游应用传递请求头。</p><hr><h2 id="场景二-使用-nginx、caddy、apache-等反向代理" tabindex="-1">场景二：使用 Nginx、Caddy、Apache 等反向代理 <a class="header-anchor" href="#场景二-使用-nginx、caddy、apache-等反向代理" aria-label="Permalink to &quot;场景二：使用 Nginx、Caddy、Apache 等反向代理&quot;">​</a></h2><p>反向代理部署时，Dashboard 看到的连接 IP 通常是反向代理服务器的 IP。你需要让反向代理把客户端 IP 写入一个 Header，然后在 Dashboard 的 <strong>前端真实 IP 请求头</strong> 中填写同名 Header。</p><p>常见选择：</p><ul><li>使用标准习惯的 <code>X-Real-IP</code>。</li><li>如果沿用本站 <a href="/guide/q3.html">反向代理配置</a> 示例，可以填写 <code>nz-realip</code>。</li><li>如果使用 <code>X-Forwarded-For</code>，请确保代理链路可信，并确认 Dashboard 读取到的是期望的客户端 IP。</li></ul><h3 id="nginx-最小示例" tabindex="-1">Nginx 最小示例 <a class="header-anchor" href="#nginx-最小示例" aria-label="Permalink to &quot;Nginx 最小示例&quot;">​</a></h3><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-For $proxy_add_x_forwarded_for;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:8008;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Dashboard 中填写：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;X-Real-IP&quot;</span></span></code></pre></div><p>如果你使用文档中的 <code>nz-realip</code> 示例：</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nz-realip $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:8008;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Dashboard 中填写：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nz-realip&quot;</span></span></code></pre></div><h3 id="caddy-最小示例" tabindex="-1">Caddy 最小示例 <a class="header-anchor" href="#caddy-最小示例" aria-label="Permalink to &quot;Caddy 最小示例&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com {</span></span>
<span class="line"><span>    reverse_proxy 127.0.0.1:8008 {</span></span>
<span class="line"><span>        header_up X-Real-IP {remote_host}</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Dashboard 中填写：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;X-Real-IP&quot;</span></span></code></pre></div><hr><h2 id="场景三-使用-cloudflare-或其它-cdn" tabindex="-1">场景三：使用 Cloudflare 或其它 CDN <a class="header-anchor" href="#场景三-使用-cloudflare-或其它-cdn" aria-label="Permalink to &quot;场景三：使用 Cloudflare 或其它 CDN&quot;">​</a></h2><p>使用 Cloudflare 代理 Dashboard 时，Dashboard 中填写：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CF-Connecting-IP&quot;</span></span></code></pre></div><p>其它 CDN 请填写该 CDN 提供的真实客户端 IP Header，例如厂商文档中说明的 Real IP、Client IP 或 Connecting IP Header。</p><p>请确保只有可信 CDN 或反向代理能访问 Dashboard 源站。如果源站仍可被公网直接访问，攻击者可以绕过 CDN 并伪造 Header。</p><hr><h2 id="waf-如何使用这个-ip" tabindex="-1">WAF 如何使用这个 IP <a class="header-anchor" href="#waf-如何使用这个-ip" aria-label="Permalink to &quot;WAF 如何使用这个 IP&quot;">​</a></h2><p>Dashboard 内置 WAF 会按 <strong>IP + 封禁标识</strong> 记录风险行为。当出现以下情况时，WAF 会记录并封禁对应来源：</p><ul><li>登录失败次数过多。</li><li>OAuth2 登录爆破。</li><li>API Token 爆破。</li><li>Agent 连接密钥爆破。</li><li>管理员在“在线用户”页面手动封禁。</li></ul><p>同一条记录的次数越多，封禁时间越长。管理员可以在 <strong>系统设置 → Web 应用防火墙</strong> 中查看封禁 IP、封禁标识、计数、封禁原因和封禁时间，也可以删除单条或批量删除封禁记录。</p><hr><h2 id="配置错误会怎样" tabindex="-1">配置错误会怎样 <a class="header-anchor" href="#配置错误会怎样" aria-label="Permalink to &quot;配置错误会怎样&quot;">​</a></h2><p>如果填写了不存在、不可信或代理没有传递的 Header，可能出现以下问题：</p><ul><li>Dashboard 无法取得 IP，在线用户和审计记录不准确。</li><li>所有访问者都被识别为反向代理或 CDN 的 IP，导致多人共用一个封禁记录。</li><li>用户可以伪造 Header，绕过 WAF 或让其他 IP 被误封。</li><li>管理员自己的 IP 被误封，导致无法登录后台。</li></ul><p>不确定时，先留空或选择 <strong>使用直连 IP</strong>，确认反向代理确实传递了正确 Header 后再启用自定义 Header。</p><hr><h2 id="如何验证" tabindex="-1">如何验证 <a class="header-anchor" href="#如何验证" aria-label="Permalink to &quot;如何验证&quot;">​</a></h2><p>保存配置并重启 Dashboard 后，可以这样验证：</p><ol><li>使用浏览器访问 Dashboard。</li><li>进入 <strong>系统设置 → 在线用户</strong>，查看自己的 IP 是否为真实客户端公网 IP，而不是反向代理、CDN 或内网地址。</li><li>检查反向代理访问日志，确认日志中的客户端 IP 与 Dashboard 在线用户页一致。</li><li>如有条件，可在反向代理临时记录传给 Dashboard 的 Header，确认 Header 名和值与 <code>web_real_ip_header</code> 完全一致。</li></ol><p>请不要通过故意连续输错密码来测试 WAF，避免把自己或其他用户误封。</p><hr><h2 id="如何恢复" tabindex="-1">如何恢复 <a class="header-anchor" href="#如何恢复" aria-label="Permalink to &quot;如何恢复&quot;">​</a></h2><p>如果配置错误导致 IP 识别异常或无法登录：</p><ol><li><p>修改 Dashboard 配置文件，一般路径为 <code>/data/config.yaml</code>。</p></li><li><p>将 <code>web_real_ip_header</code> 设置为空值或直连模式：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span></code></pre></div><p>或：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">web_real_ip_header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NZ::Use-Peer-IP&quot;</span></span></code></pre></div></li><li><p>重启 Dashboard。</p></li><li><p>重新登录后台，在 <strong>系统设置 → Web 应用防火墙</strong> 删除误封的 IP 或相关封禁记录。</p></li></ol><p>如果你已经能进入后台，也可以直接在系统设置中修改 <strong>前端真实 IP 请求头</strong> 并保存，然后到 WAF 页面删除对应封禁记录。</p>`,57),n=[l];function d(p,h,r,o,c,k){return i(),s("div",null,n)}const u=a(t,[["render",d]]);export{b as __pageData,u as default};
